const BLOCK_OF_THREE_BASE = 60;

const isBlockOfThree = (items: QuoteItem[]): boolean =>
  items.length === 3 && items.every((item) => item.type === items[0].type);

const sumOfBasePremiums = (items: QuoteItem[]): number =>
  items.reduce((sum, item) => sum + basePremiums[item.type], 0);

export function runScenario(scenario: Scenario): ScenarioResult {
  const results = scenario.steps.map((step) => {
    const basePremium = isBlockOfThree(step.items)
      ? BLOCK_OF_THREE_BASE
      : sumOfBasePremiums(step.items);
    return { premium: basePremium + PROCESSING_FEE };
  });
  return { results };
}

